import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void needsToOffsetInitialDip() {
        // prefix sums: -5, 5, -3. min=-5. starting balance must be 5.
        // Verify: 5 + (-5) = 0 ≥ 0, 0 + 10 = 10, 10 + (-8) = 2. ✓
        assertEquals(5, new Solution().minStartingBalance(new int[]{-5, 10, -8}));
    }

    @Test
    void dipAfterCreditBurst() {
        // prefix: 10, 15, -5. min=-5. start=5.
        assertEquals(5, new Solution().minStartingBalance(new int[]{10, 5, -20}));
    }

    @Test
    void allCredits() {
        // prefix: 5, 15, 35. min=5 (positive). start=0.
        assertEquals(0, new Solution().minStartingBalance(new int[]{5, 10, 20}));
    }

    @Test
    void singleHugeDebit() {
        assertEquals(100, new Solution().minStartingBalance(new int[]{-100}));
    }

    @Test
    void empty() {
        assertEquals(0, new Solution().minStartingBalance(new int[]{}));
    }
}
